import re; push=open('.github/scripts/render-push.js').read(); push=re.sub(r'\.glow \{[^}]+\}',''.join(['.glow { position: absolute; inset: 0; border-radius: 80px; background: conic-gradient(from 270deg, #F5B8A0 0%, #E080A0 25%, #8B5CF6 50%, #E080A0 75%, #F5B8A0 100%); filter: blur(40px); opacity: 0.85; z-index: 0; }']),push,flags=re.DOTALL); push=push.replace('height: 160px; object-fit: cover;','height: 220px; object-fit: cover;'); push=push.replace('margin: 40px;',''); push=push.replace('.phone-wrap { position: relative; width: 380px; }','.phone-wrap { position: relative; width: 460px; padding: 60px; box-sizing: content-box; display: flex; align-items: center; justify-content: center; }'); push=push.replace('height: 900 }','height: 1100 }'); open('.github/scripts/render-push.js','w').write(push); sms=open('.github/scripts/render-sms.js').read(); sms=sms.replace('flex: 1; overflow: hidden;','flex-grow: 1; overflow: hidden;'); sms=sms.replace('gap: 7px; }','gap: 7px; position: absolute; bottom: 0; left: 0; right: 0; background: #000; }'); sms=sms.replace("await page.waitForTimeout(1000)","await page.waitForTimeout(1000);await page.evaluate(() => { const s = document.querySelector('.screen'); if(s) s.scrollTop = s.scrollHeight; })"); open('.github/scripts/render-sms.js','w').write(sms); print('patched')